import xml.etree.ElementTree as ET
from lxml import etree, html

def validate_and_parse_xml(xml_file):
    schema_file = "path/to/your/xsd-file"  # Replace with your schema file path

    validator = etree.XMLSchema(etree.parse(schema_file))
    parsed_xml = ET.parse(xml_file)

    try:
        validator.validate(parsed_xml)
        return html.fromstring(parsed_xml.write('utf-8'))  # Parse the XML with lxml for further processing if needed
    except etree.XMLSyntaxError as e:
        print("Invalid XML document:", e)